"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[469],{4988:e=>{e.exports=JSON.parse('{"functions":[{"name":"Shatter","desc":"`Shatter(Config)` when the controller has a [Host], Target is implied. `Shatter(Target, Config)`\\notherwise. `Hitbox` is optional in either form - omit it to shatter the whole Target/Host\\ndirectly with no detection step.\\n\\nA third form: `Shatter(Config)` with **no Host and a `Hitbox`** runs indiscriminate\\ndestruction - there\'s no single Target, so the hitbox queries `hitbox.Scope` (default the\\nwhole `workspace`) directly and shatters whatever it finds, regardless of which part it came\\nfrom. `Result.Instance` is `nil` for this form, since no one Target/Host exists.","params":[{"name":"a","desc":"a Target when the controller has no Host, otherwise the ShatterConfig directly.","lua_type":"Instance | ShatterConfig"},{"name":"b","desc":"the config, when `a` was a Target.","lua_type":"ShatterConfig?"}],"returns":[{"desc":"chain off it with `:Next(Enums.Event.X):Then(callback)`.","lua_type":"PendingResult"}],"function_type":"method","source":{"line":604,"path":"src/VoxelController/init.luau"}},{"name":"Start","desc":"Flushes the `Timeline` queue in call order. No-op for `Instant` controllers - they never queue,\\nevery `:Shatter()` call already ran by the time it returns.","params":[],"returns":[],"function_type":"method","source":{"line":638,"path":"src/VoxelController/init.luau"}},{"name":"Destroy","desc":"Clears any queued `Timeline` jobs that haven\'t run yet. Doesn\'t touch parts already produced\\nby past `:Shatter()` calls - those live on independently under `workspace._Bin.Voxels`.","params":[],"returns":[],"function_type":"method","source":{"line":653,"path":"src/VoxelController/init.luau"}}],"properties":[],"types":[{"name":"HitboxConfig","desc":"","fields":[{"name":"Size","lua_type":"Vector3?","desc":"box/region extents, in studs, centered on `CFrame`. Ignored by `Raycast`."},{"name":"CFrame","lua_type":"CFrame?","desc":"where the hitbox sits in the world. Defaults to `CFrame.new()` (the origin) if omitted."},{"name":"ViewVector","lua_type":"Vector3?","desc":"cast direction for `QueryType.Raycast` only; ignored by every other QueryType."},{"name":"Color","lua_type":"Color3?","desc":"cosmetic only - tints a visualized hitbox if you render one yourself. Facet never draws it for you."},{"name":"QueryType","lua_type":"Enums.QueryType?","desc":"`Box` (default) | `Sphere` | `Region` | `Raycast`. Picks which exact-shape test runs after the octree broad phase."},{"name":"HitboxType","lua_type":"Enums.HitboxType?","desc":"`Partial` (default, voxelizes whatever\'s detected) | `Whole` (returns fully-contained parts untouched, no slicing)."},{"name":"Shape","lua_type":"Enum.PartType?","desc":"reserved for a future visualized-hitbox helper; not read by Shatter today."},{"name":"Copy","lua_type":"Instance?","desc":"reserved for a future \\"clone the hitbox as a real part\\" helper; not read by Shatter today."},{"name":"Scope","lua_type":"Instance?","desc":"only read when `Shatter` is called with no Target and no Host (indiscriminate destruction) - restricts the workspace-wide query to this instance\'s descendants. Defaults to the whole `workspace`. Ignored otherwise (a Target/Host already scopes the search)."}],"source":{"line":72,"path":"src/VoxelController/init.luau"}},{"name":"CleanupConfig","desc":"","fields":[{"name":"Method","lua_type":"(Enums.Cleanup | (Voxel) -> ())?","desc":"`Rebuild` | `Fade` | `Destroy`, or your own `function(voxel) ... end`. Only ever runs against `Result.Voxels.Partial`."},{"name":"Delay","lua_type":"number?","desc":"seconds the Cleanup tween takes (`Fade`/`Rebuild` only - `Destroy` is instant). Defaults to 0.5 for Fade, 0.6 for Rebuild."}],"source":{"line":90,"path":"src/VoxelController/init.luau"}},{"name":"ShatterConfig","desc":"","fields":[{"name":"Hitbox","lua_type":"HitboxConfig?","desc":"scopes detection to a region of the target. Omit entirely to voxelize the whole target."},{"name":"Effects","lua_type":"{[string]: any}?","desc":"keyed by `Enums.Effects` - see [Enums.Effects] for the full list and each one\'s config shape."},{"name":"Cleanup","lua_type":"CleanupConfig?","desc":"`{ Method = Enums.Cleanup.X, Delay = number? }`, or your own `{ Method = function(voxel) ... end }`."}],"source":{"line":102,"path":"src/VoxelController/init.luau"}},{"name":"DefineConfig","desc":"","fields":[{"name":"Type","lua_type":"Enums.ControllerType","desc":"`Relative` (dynamic sizing, requires `RecommendedVoxelSize`) or `Absolute` (fixed `VoxelSize`). Required."},{"name":"RuntimeType","lua_type":"Enums.RuntimeType?","desc":"`Instant` (default, runs every Shatter immediately) or `Timeline` (queues calls until `:Start()`)."},{"name":"Host","lua_type":"Instance?","desc":"scopes every Shatter call on this controller to one instance without naming a Target each time."},{"name":"MinimumVoxelSize","lua_type":"number?","desc":"Relative only. Floor `Shatter` will shrink voxels to under load. Defaults to `RecommendedVoxelSize` (no shrink) if omitted."},{"name":"RecommendedVoxelSize","lua_type":"number?","desc":"Relative only. Target voxel size the controller sizes toward. Required for `Relative`."},{"name":"Drivers","lua_type":"{VoxelizationMethod: string?}?","desc":"reserved for swapping the slicing backend; not read by Shatter today."},{"name":"VoxelSize","lua_type":"number?","desc":"Absolute only. The fixed cube size every voxel is sliced to. Required for `Absolute`."}],"source":{"line":119,"path":"src/VoxelController/init.luau"}}],"name":"VoxelController","desc":"Returned by [Facet.Define]. Owns one Shatter pipeline: resolve candidate parts, optionally\\nclassify them against a [HitboxConfig], voxelize, apply Effects, run Cleanup, and fire a\\n[Result] through the [PendingResult] chain. Typed explicitly (never `any`) so every field\\nand method below has real Intellisense.","source":{"line":136,"path":"src/VoxelController/init.luau"}}')}}]);